solution: ```class Solution {
public:
    int leastOpsExpressTarget(int x, int target) {
        int ops = 0;
        while (target) {
            int k = 0;
            long p = 1;
            while (p * x <= target) {
                p *= x;
                ++k;
            }
            if (p == target) return ops + k - 1;
            int rem = target % p;
            if (rem == 0) return ops + k - 1 + (target / p - 1);
            int cand1 = ops + k + leastOpsExpressTarget(x, rem);
            int cand2 = ops + k + 1 + leastOpsExpressTarget(x, p - rem);
            if (p - rem < rem) {
                return cand2;
            } else {
                return cand1;
            }
        }
        return 0;
    }
};
```
